<?php
namespace App\Models;use Illuminate\Database\Eloquent\Model;use Illuminate\Database\Eloquent\SoftDeletes;
class WorkerPayoutReviewEvidence extends Model{use SoftDeletes;protected $table='worker_payout_review_evidence';protected $fillable=['worker_payout_review_id','worker_id','uploaded_by_id','status','evidence_type','original_filename','stored_disk','stored_path','mime_type','size_bytes','sha256_hash','visibility','reviewer_note','rejection_reason','metadata'];protected $hidden=['stored_path','reviewer_note','metadata'];protected function casts():array{return ['metadata'=>'array'];}public function review(){return $this->belongsTo(WorkerPayoutReview::class,'worker_payout_review_id');}public function events(){return $this->hasMany(WorkerPayoutReviewEvidenceEvent::class,'evidence_id')->latest('created_at');}}
